// lib/features/auth/domain/entities/user.dart
class User { const User({required this.id, required this.email}); final int id; final String email; }

// lib/features/auth/domain/repositories/auth_repository.dart
abstract class AuthRepository { Future<User> signIn(String email, String password); }

// lib/features/auth/domain/usecases/sign_in.dart
class SignIn {
  SignIn(this._repo);
  final AuthRepository _repo;
  Future<User> call(String email, String password) => _repo.signIn(email, password);
}

// lib/features/auth/data/repositories/auth_repository_impl.dart
class AuthRepositoryImpl implements AuthRepository {
  AuthRepositoryImpl(this._api);
  final Dio _api;
  @override
  Future<User> signIn(String email, String password) async {
    final r = await _api.post('/login', data: {'email': email, 'password': password});
    return User(id: r.data['id'], email: r.data['email']);
  }
}

// lib/features/auth/presentation/viewmodels/sign_in_view_model.dart
class SignInViewModel extends ChangeNotifier {
  SignInViewModel(this._signIn);
  final SignIn _signIn;
  bool loading = false; String? error; User? user;

  Future<void> submit(String email, String password) async {
    loading = true; error = null; notifyListeners();
    try { user = await _signIn(email, password); }
    catch (e) { error = e.toString(); }
    finally { loading = false; notifyListeners(); }
  }
}

// lib/features/auth/presentation/screens/sign_in_screen.dart
class SignInScreen extends StatelessWidget { ... }

// lib/features/auth/auth_di.dart — each feature exposes its own DI setup
void registerAuthFeature() {
  getIt.registerFactory<AuthRepository>(() => AuthRepositoryImpl(getIt<Dio>()));
  getIt.registerFactory<SignIn>(() => SignIn(getIt<AuthRepository>()));
  getIt.registerFactory<SignInViewModel>(() => SignInViewModel(getIt<SignIn>()));
}

// Then in main.dart's setupDI():
void setupDI() {
  getIt.registerSingleton<Dio>(Dio());
  registerAuthFeature();
  registerCartFeature();
  registerCheckoutFeature();
}

// Each feature is a self-contained slice. Adding a new feature =
// create `lib/features/newthing/` + register its DI. That's it.
